query_examples.query:
query GetInstrumentByISIN {
  instruments(filter: { isinCode: "US0378331005" }) {
    instrumentId
    instrumentName
    instrumentTypeCode
    assetClassCode
    currencyCode
    statusCode
    issueDate
    maturityDate
  }
}

query GetParty($id: ID!) {
  party(partyId: $id) {
    partyId
    legalName
    shortName
    partyTypeCode
    leiCode
    countryCode
    regionCode
    statusCode
  }
}
